# terraform/global-lb.tf
# Route 53 latency-based routing with health checks for multi-region failover

resource "aws_route53_health_check" "primary" {
  fqdn              = "agent-primary.us-east-1.internal.example.com"
  port              = 443
  type              = "HTTPS"
  resource_path     = "/health"
  failure_threshold = 3
  request_interval  = 10
  tags = { Name = "agent-primary-health" }
}

resource "aws_route53_record" "primary" {
  zone_id = var.hosted_zone_id
  name    = "agent.example.com"
  type    = "A"

  set_identifier = "primary-us-east-1"
  health_check_id = aws_route53_health_check.primary.id

  failover_routing_policy {
    type = "PRIMARY"
  }

  alias {
    name                   = aws_lb.primary.dns_name
    zone_id                = aws_lb.primary.zone_id
    evaluate_target_health = true
  }
}

resource "aws_route53_record" "standby" {
  zone_id = var.hosted_zone_id
  name    = "agent.example.com"
  type    = "A"

  set_identifier = "standby-eu-west-1"

  failover_routing_policy {
    type = "SECONDARY"
  }

  alias {
    name                   = aws_lb.standby.dns_name
    zone_id                = aws_lb.standby.zone_id
    evaluate_target_health = true
  }
}
